CREATE TABLE `print_jobs` (
  `job_id` varchar(10) NOT NULL,
  `user_id` varchar(10) DEFAULT NULL,
  `printer_id` varchar(10) DEFAULT NULL,
  `print_time` datetime DEFAULT NULL,
  `page_count` int DEFAULT NULL,
  `duplex` tinyint(1) DEFAULT NULL,
  `color` tinyint(1) DEFAULT NULL,
  `paper_size` varchar(10) DEFAULT NULL,
  `document_type` varchar(50) DEFAULT NULL,
  `cost` float DEFAULT NULL,
  PRIMARY KEY (`job_id`),
  KEY `user_id` (`user_id`),
  KEY `printer_id` (`printer_id`),
  CONSTRAINT `print_jobs_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`),
  CONSTRAINT `print_jobs_ibfk_2` FOREIGN KEY (`printer_id`) REFERENCES `printers` (`printer_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
